-- ============================================
-- 查询「多账户规则保存test」选中的 18 个广告在 ad_snapshots 中的数据
-- 表 ad_snapshots 无 impressions 列，已按实际 schema 只选存在列
-- ============================================

-- （1）今天 data_date 的数据（与规则「花费>0 今天」口径一致）
SELECT
  s.account_id,
  s.ad_id,
  s.data_date,
  s.spend,
  s.status,
  s.timezone_name,
  s.synced_at,
  a.name AS ad_name
FROM ad_snapshots s
LEFT JOIN structure_ads a ON a.account_id = s.account_id AND a.ad_id = s.ad_id
WHERE (s.account_id, s.ad_id) IN (
  ('act_809037544823254', '120239336195840687'),
  ('act_1097578525869755', '120238001334880426'),
  ('act_1120871463163565', '120239390327280374'),
  ('act_1120871463163565', '120241350385510374'),
  ('act_1155891202142879', '120236876211260501'),
  ('act_1155891202142879', '120236941795230501'),
  ('act_1263098958612251', '120239820785860277'),
  ('act_1263098958612251', '120239992138510277'),
  ('act_1311074497415630', '120239065831130498'),
  ('act_1311074497415630', '120239303902570498'),
  ('act_1313346806321636', '120239286193540446'),
  ('act_1313346806321636', '120239286193560446'),
  ('act_1498921711073041', '120240679780870639'),
  ('act_1498921711073041', '120240679780950639'),
  ('act_1501999950830277', '120232093800800760'),
  ('act_1501999950830277', '120235273305100760'),
  ('act_1905531400268801', '120240689210020251'),
  ('act_1905531400268801', '120240689210060251')
)
AND s.data_date = CURDATE()
ORDER BY s.account_id, s.ad_id;


-- （2）不限 data_date：看这 18 个广告最近是否有任意日期数据
SELECT
  s.account_id,
  s.ad_id,
  s.data_date,
  s.spend,
  s.status,
  s.synced_at
FROM ad_snapshots s
WHERE (s.account_id, s.ad_id) IN (
  ('act_809037544823254', '120239336195840687'),
  ('act_1097578525869755', '120238001334880426'),
  ('act_1120871463163565', '120239390327280374'),
  ('act_1120871463163565', '120241350385510374'),
  ('act_1155891202142879', '120236876211260501'),
  ('act_1155891202142879', '120236941795230501'),
  ('act_1263098958612251', '120239820785860277'),
  ('act_1263098958612251', '120239992138510277'),
  ('act_1311074497415630', '120239065831130498'),
  ('act_1311074497415630', '120239303902570498'),
  ('act_1313346806321636', '120239286193540446'),
  ('act_1313346806321636', '120239286193560446'),
  ('act_1498921711073041', '120240679780870639'),
  ('act_1498921711073041', '120240679780950639'),
  ('act_1501999950830277', '120232093800800760'),
  ('act_1501999950830277', '120235273305100760'),
  ('act_1905531400268801', '120240689210020251'),
  ('act_1905531400268801', '120240689210060251')
)
ORDER BY s.account_id, s.ad_id, s.data_date DESC;
